(function(){function toRGB(code){if(code.length===4){code=code[1]+code[1]+code[2]+code[2]+code[3]+code[3]}var hex=/(\w{2})(\w{2})(\w{2})/.exec(code);return[parseInt(hex[1],16),parseInt(hex[2],16),parseInt(hex[3],16)]}function toHex(ary){return"#"+ary.map(function(i){var hex=i.toString(16);return hex.length===1?"0"+hex:hex}).join("")}function colorIncrement(color,range){var startRGB=toRGB(color.start);var endRGB=toRGB(color.end);return endRGB.map(function(n,i){return(n-startRGB[i])/range})}function tagColor(color,increment,weighting){var startRGB=toRGB(color.start);return toHex(startRGB.map(function(n,i){return Math.min(255,Math.max(0,Math.round(n+increment[i]*weighting)))}))}window.tagcloud=function(elements,options){var defaults={size:{start:14,end:18,unit:"pt"}};var opts=Object.assign({},defaults,options);var weights=Array.from(elements).map(function(el){return parseInt(el.getAttribute("rel"),10)}).sort(function(a,b){return a-b});var lowest=weights[0];var highest=weights[weights.length-1];var range=highest-lowest||1;var fontIncr,colorIncr;if(opts.size)fontIncr=(opts.size.end-opts.size.start)/range;if(opts.color)colorIncr=colorIncrement(opts.color,range);elements.forEach(function(el){var weighting=parseInt(el.getAttribute("rel"),10)-lowest;if(opts.size){el.style.fontSize=opts.size.start+weighting*fontIncr+opts.size.unit}if(opts.color){el.style.backgroundColor=tagColor(opts.color,colorIncr,weighting)}})}})();